const e="/assets/MDMS%20for%20utility%20Billing-B8kYdB6B.webp",t="/assets/Ongoing%20Project%20%E2%80%93%20Smart%20Street%20Lighting%20Control%20%202-vMqwwvHO.png",m=[{id:101,title:"MDMS for Utility Billing",location:"Dubai, UAE",shortDesc:"Implementing a large-scale Meter Data Management System (MDMS) for a leading utility billing company in Dubai.",image:e,details:{content:["ConnectME Manufacturing LLC is currently implementing a large-scale Meter Data Management System (MDMS) for a leading utility billing company in Dubai, designed to support modern, transparent, and scalable utility operations across the city.","Powered by our UBILL-AMR AI platform, the deployment currently manages over 25,000 smart meter nodes across 135 buildings, enabling fully automated, accurate, and reliable meter data acquisition for utility billing and operational analytics.","Our smart MDMS platform provides real-time visibility into building performance, energy and water consumption patterns, and system health, allowing operators to monitor assets centrally and proactively detect anomalies. Advanced data validation and integrity checks ensure consistent, tamper-resistant data flow from meters to the billing system.","By significantly reducing manual meter reading, minimizing billing disputes, and improving data accuracy, the solution enhances operational efficiency and customer trust. The system is built with a scalable, future-ready architecture, supporting city-wide expansion, advanced analytics, and seamless integration with existing utility billing and enterprise systems—strengthening Dubai’s smart infrastructure ecosystem."],quote:"This deployment demonstrates ConnectME’s capability to deliver secure, scalable, and AI-driven MDMS solutions for modern utility billing and smart city ecosystems."}},{id:102,title:"Smart Street Lighting Control System",location:"Communities, UAE",shortDesc:"Successfully implemented a Smart Street Lighting Control System for large-scale outdoor lighting across multiple communities.",image:t,details:{content:["ConnectME Manufacturing LLC has successfully implemented a Smart Street Lighting Control System for large-scale outdoor lighting across multiple communities and residential parks within Communities.","The solution leverages ConnectME’s cloud-based lighting management platform integrated with UCONNECT EDGE controllers installed at street-light feeder panels. Using the cloud platform, year-long lighting schedules are centrally configured and securely pushed to edge devices, enabling precise, real-time ON/OFF control of street lighting systems.","The platform supports both automatic and manual operation modes, allowing lighting assets to be grouped into zones and controlled remotely by the operations team. In addition to lighting control, the system provides real-time energy monitoring for each feeder, offering valuable insights into consumption and operational efficiency.","A dedicated maintenance and asset management module enables field teams to track assets, log maintenance activities, and respond proactively to faults. The cloud engine automatically generates daily, weekly, and monthly reports, including energy usage, operational status, trips, and error events—ensuring complete visibility and auditability of the lighting infrastructure.","To enhance operational responsiveness, automated alerts and notifications are triggered by the EDGE controllers under abnormal conditions. These alerts are delivered via WhatsApp groups shared across maintenance teams, operations teams, and community management—ensuring faster fault resolution and uninterrupted lighting services.","The deployment empowers community teams with a reliable, scalable, and intelligent street lighting system, simplifying asset management, reducing operational overheads, and improving overall service quality across communities."],features:[{label:"Centralized Cloud Lighting Control",desc:"Configure and manage street lighting schedules centrally through a secure cloud platform."},{label:"Year-Round Automated Scheduling",desc:"Predefined ON/OFF schedules pushed directly to edge devices for reliable operation."},{label:"Real-Time Energy Monitoring",desc:"Live monitoring of energy consumption for each feeder panel."},{label:"AUTO & Manual Operation",desc:"Flexible control with zoning, overrides, and manual command execution from the cloud."},{label:"Maintenance & Asset Management",desc:"Track lighting assets, maintenance activities, and fault history in one platform."},{label:"Automated Reports & Analytics",desc:"Daily, weekly, and monthly reports covering energy, faults, trips, and system health."},{label:"Instant Alerts & WhatsApp Notifications",desc:"Automated alerts triggered by EDGE devices and delivered instantly to teams."},{label:"UCONNECT EDGE – Multi-Protocol Gateway",desc:"Supports MQTT, HTTPS, FTP, Modbus, BACnet, and LoRaWAN forwarder gateway for seamless integration."}],quote:"This smart street lighting deployment demonstrates ConnectME’s capability to deliver cloud-driven, edge-enabled infrastructure solutions that enhance operational efficiency, asset visibility, and community service excellence."}}],a="/assets/THE%20PALM%20TOWER-DoLTTzUP.webp",i="/assets/FIVE%20LUXE_%20JBR-CUFoCYZg.webp",n="/assets/Festival%20Plaza%20Mall-BW_Wl9wC.webp",l="/assets/Dubai%20Hills%20Park%20-%20IoT%20Lighting-B-0ECUw7.webp",o="/assets/Via%20Riyadh%20Mall-DGHJ78Bw.webp",s="/assets/National%20Centre%20of%20Meteorology-DJVhJN4s.webp",r="/assets/Laysen%20Valley-BPykoKAc.webp",d="/assets/Maternity%20and%20Children%20Hospital-BIqTS9kN.webp",c="/assets/King%20Salman%20Specialist%20Hospital-BVO5JhNX.webp",g=[{id:1,title:"The Palm Tower",location:"Dubai, UAE",desc:"Implemented centralized IBM Meter Data Management platform integrating five different BTU meter brands. Standardized meter data collection, processing, and reporting across all brands, enabling real-time monitoring and fault detection.",image:a},{id:2,title:"Five Luxe, JBR",location:"JBR, Dubai, UAE",desc:"Integrated BTU, Hot Water, Cold Water, and Flush Water meters into a centralized IBM AMR software platform. Enabled automated meter reading for all utilities, improving billing accuracy and reducing manual data handling.",image:i},{id:3,title:"Festival Plaza Mall",location:"Dubai, UAE",desc:"Deployed non-intrusive clamp-on BTU meters for accurate energy monitoring across retail outlets. The solution avoided system shutdowns and integrated seamlessly with the BMS, delivering billing-grade accuracy.",image:n},{id:4,title:"Dubai Hills Park - IoT Street Lighting",location:"Dubai, UAE",desc:"IoT-based connectivity solution for feeder pillars with remote ON/OFF control and real-time power monitoring. Integrated with a cloud platform for centralized management of street lighting.",image:l},{id:5,title:"VIA Riyadh Mall",location:"Riyadh, KSA",desc:"MBUS BTU and Electric meters data integration to IBM Software 150node for data analysis and billing.",image:o},{id:6,title:"National Centre of Meteorology",location:"Jeddah, KSA",desc:"Supply and installation of Teckhnave Clamp on BTU/Flow Meter.",image:s},{id:7,title:"Laysen Valley",location:"Riyadh, KSA",desc:"BTU meters, Hot Water, Cold water and Electric Meter data integration to IBM Software 600 nodes for data analysis and billing.",image:r},{id:8,title:"Maternity and Children Hospital",location:"Hail, KSA",desc:"Supply and installation of Teckhnave Clamp on BTU/Flow Meter.",image:d},{id:9,title:"King Salman Specialist Hospital",location:"KSA",desc:"Supply and installation of Teckhnave Clamp on BTU/Flow Meter.",image:c}];export{m as a,g as p};
